import "./App.css";
import React, { useRef, useState } from "react";

function App() {
  const contentEl = useRef(null);
  const [isContentVisible, setContentVisibility] = useState(false);
  const [isSubContentVisible, setSubContentVisibility] = useState(false);

  const handleClick = () => {
    console.log("Button was clicked");
    setContentVisibility(!isContentVisible);
  };

  const handleSubClick = () => {
    console.log("Sub Button was clicked");
    setSubContentVisibility(!isSubContentVisible);
  };

  return (
    <div>
      <button
        id="collapsible-button"
        type="button"
        className="collapsible"
        onClick={handleClick}
      >
        Open Collapsible
      </button>
      <div
        ref={contentEl}
        className={`${isContentVisible ? "visible" : "hidden"} content`}
      >
        <button className="ctgry" onClick={handleSubClick}>
          Cleaning Supplies
        </button>
        <button className="ctgry">Lorem ipsum...</button>
        <button className="ctgry">Lorem ipsum...</button>
        <button className="ctgry">Lorem ipsum...</button>
        <button className="ctgry">Lorem ipsum...</button>
        <div
          className={`${
            isSubContentVisible ? "visible" : "hidden"
          } sub-content`}
        >
          <button className="sub-ctgry">Paper Towels</button>
          <button className="sub-ctgry">Lorem ipsum...</button>
          <button className="sub-ctgry">Lorem ipsum...</button>
          <button className="sub-ctgry">Lorem ipsum...</button>
          <button className="sub-ctgry">Lorem ipsum...</button>
        </div>
      </div>
    </div>
  );
}

export default App;
